//   [0x68..0x6F] = ???
//   [0x78..0x87] = float viewProjMatrix[4][4]
//   [0x88..0x8B] = float4 eyeForward
//   [0x8C..0x9B] = float viewMatrix[4][4]
//   [0x9C..0xAB] = float invViewMatrix[4][4]
//   [0xC1]       = byte reflectionFlag
//   [0xC2]       = byte reflectionEyeOffset[3]  (x,y,z offsets)
